        "population = [25000, 27000, 45000, 34000]\n",
        "s = pd.Series(population, index=cities)\n",
        "s.plot(kind='bar', width=0.5, color=\"red\")\n",
        "plt.xlabel(\"Cities\")\n",
        "plt.ylabel(\"Population\")\n",
        "plt.title(\"Clean City Data Analysis\")\n",
        "plt.show()"
